  ('aboriginal-6f0ba476-moex-00302', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-6ed013db', 'sub-aboriginal-6f0ba476-06', NULL, 'single_choice', '森林法第15條第4項所稱生活慣俗之認定有疑義時，應由受理原住民族提案採取森林產物之機關，函請 何機關協助認定？', '["內政部", "教育部", "農業部", "原住民族委員會"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:55+00:00", "source_pdf_sha1": "384194208de1", "answer_pdf_sha1": "a334f7cbe936", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00303', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-6ed013db', 'sub-aboriginal-6f0ba476-06', NULL, 'single_choice', '依原住民保留地禁伐補償條例，關於原住民保留地之禁伐及補償規定，下列敘述何者錯誤？', '["申請人非土地所有權人者不得申請", "中華民國106年起，禁伐補償金額度為每年每公頃新臺幣3萬元", "原住民保留地依法編定為林業用地或適用林業用地管制者，由主管機關劃定為禁伐區域並公告之", "禁伐補償金核發後，申請人喪失原住民身分者，應撤銷禁伐補償，並命受領人按月依比例返還當年度之 禁伐補償金"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:55+00:00", "source_pdf_sha1": "384194208de1", "answer_pdf_sha1": "a334f7cbe936", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
