  ('aboriginal-6f0ba476-moex-00305', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-6ed013db', 'sub-aboriginal-6f0ba476-06', NULL, 'single_choice', '主管機關為審議各類原住民族文化資產所涉文化資產保存法規定之重大事項，應設原住民族文化資產審議 會，專責審議原住民族文化資產；此一審議會的人員組成，依原住民族文化資產處理辦法規定，應有多少 比例以上為非機關人員？', '["二分之一", "三分之一", "三分之二", "四分之三"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:55+00:00", "source_pdf_sha1": "384194208de1", "answer_pdf_sha1": "a334f7cbe936", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00306', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-6ed013db', 'sub-aboriginal-6f0ba476-06', NULL, 'single_choice', '依原住民族教育法規定，中央政府應寬列預算，專款辦理原住民族教育；其比率，合計不得少於中央教育 主管機關預算總額百分之一點九，並係以教育部及原住民族委員會編列之本經費數額合計，試問：兩部會 各自分擔的比率為何？', '["教育部負擔百分之六十，原住民族委員會負擔百分之四十", "教育部負擔百分之六十五，原住民族委員會負擔百分之三十五", "教育部負擔百分之七十，原住民族委員會負擔百分之三十", "教育部負擔百分之七十五，原住民族委員會負擔百分之二十五"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:55+00:00", "source_pdf_sha1": "384194208de1", "answer_pdf_sha1": "a334f7cbe936", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
